# terraform/branch_protection.tf
# Requires: hashicorp/github provider ~> 6.0

terraform {
  required_providers {
    github = {
      source  = "integrations/github"
      version = "~> 6.0"
    }
  }
}

variable "github_token" {
  type      = string
  sensitive = true
}

provider "github" {
  token = var.github_token
  owner = "my-org"
}

resource "github_branch_protection" "main" {
  repository_id = "my-genai-service"
  pattern       = "main"

  enforce_admins                  = true
  require_signed_commits          = true
  required_linear_history         = false
  require_conversation_resolution = true
  allows_force_pushes             = false
  allows_deletions                = false

  required_status_checks {
    strict = true
    contexts = [
      "lint / typecheck",
      "test / unit",
      "eval / run-evals",
      "safety / safety-scan",
      "prompt / validate-prompt-hashes",
    ]
  }

  required_pull_request_reviews {
    dismiss_stale_reviews           = true
    restrict_dismissals             = false
    require_code_owner_reviews      = true
    required_approving_review_count = 2
    require_last_push_approval      = true
  }
}

# Optional: apply the same rule to the staging branch with relaxed thresholds
resource "github_branch_protection" "staging" {
  repository_id = "my-genai-service"
  pattern       = "staging"

  enforce_admins         = false
  require_signed_commits = true
  allows_force_pushes    = false
  allows_deletions       = false

  required_status_checks {
    strict   = true
    contexts = ["lint / typecheck", "test / unit", "eval / run-evals"]
  }

  required_pull_request_reviews {
    dismiss_stale_reviews           = true
    required_approving_review_count = 1
    require_code_owner_reviews      = true
  }
}
